import{_ as i,o,c as r,ai as t}from"./chunks/framework.CaiDwmc7.js";const d=JSON.parse('{"title":"AI 时代开发者入门路线（大模型 / Agent / 多模态）【总览】","description":"","frontmatter":{},"headers":[],"relativePath":"ai/ai-roadmap.md","filePath":"ai/ai-roadmap.md"}'),n={name:"ai/ai-roadmap.md"};function a(e,l,s,g,u,p){return o(),r("div",null,[...l[0]||(l[0]=[t('<h1 id="ai-时代开发者入门路线-大模型-agent-多模态-【总览】" tabindex="-1">AI 时代开发者入门路线（大模型 / Agent / 多模态）【总览】 <a class="header-anchor" href="#ai-时代开发者入门路线-大模型-agent-多模态-【总览】" aria-label="Permalink to “AI 时代开发者入门路线（大模型 / Agent / 多模态）【总览】”">​</a></h1><blockquote><p>这篇文章是给「普通开发者」用的，不是做科研。目标很明确：<strong>在 AI 时代，怎么一步步把 LLM + Agent 真正用到项目里</strong>，先能做出原型，再逐步深入。</p></blockquote><hr><h2 id="一、整体思路-分阶段上手-而不是一下子学-全栈-ai" tabindex="-1">一、整体思路：分阶段上手，而不是一下子学“全栈 AI” <a class="header-anchor" href="#一、整体思路-分阶段上手-而不是一下子学-全栈-ai" aria-label="Permalink to “一、整体思路：分阶段上手，而不是一下子学“全栈 AI””">​</a></h2><p>你可以按这条主线来理解自己的学习路线：</p><ol><li><strong>第一阶段：核心能力 — 快速上手大模型和 Agent 系统</strong><ul><li>会用 API，能做问答、摘要、生成类工具。</li><li>知道怎么让模型“调用工具”，而不是只会聊天。</li></ul></li><li><strong>第二阶段：数据接入与中间层 — MVP Server / 数据中台</strong><ul><li>把外部数据（新闻、行情、业务数据）统一整理好，喂给模型用。</li></ul></li><li><strong>第三阶段：进阶能力 — 多模态 &amp; 知识图谱</strong><ul><li>学会用向量检索、知识库、图数据库做更复杂的问答与分析。</li></ul></li><li><strong>第四阶段（后期可选）：生成平台 &amp; MLOps</strong><ul><li>把自己的 AI 服务做成真正上线可用的产品，有部署、监控、版本管理。</li></ul></li></ol><p>下面每个阶段我都拆成了<strong>单独文章</strong>，你可以按需跳转（均在本模块下）：</p><ul><li>第一阶段：大模型（LLM）入门与 Prompt 规划 → <code>/ai/llm-basics</code></li><li>第一阶段进阶：Agent / 工具型 AI 规划（含 System Prompt / Function Calling / MCP 速记）→ <code>/ai/agent-basics</code></li><li>第二阶段：MVP Server / 数据中台规划 → <code>/ai/mvp-server</code></li><li>第三阶段：多模态 &amp; 知识图谱规划 → <code>/ai/multimodal-kg</code></li><li>第四阶段（可选）：部署 &amp; MLOps 规划 → <code>/ai/mlops-platform</code></li></ul><p>下面是压缩版总览，方便你先选阶段，再去看对应文章。</p><hr><h2 id="二、第一阶段-核心能力-—-大模型-llm-与-agent-入门" tabindex="-1">二、第一阶段：核心能力 — 大模型（LLM）与 Agent 入门 <a class="header-anchor" href="#二、第一阶段-核心能力-—-大模型-llm-与-agent-入门" aria-label="Permalink to “二、第一阶段：核心能力 — 大模型（LLM）与 Agent 入门”">​</a></h2><h3 id="_1️⃣-大模型-llm-先学会-调用-和-提示" tabindex="-1">1️⃣ 大模型（LLM）：先学会“调用”和“提示” <a class="header-anchor" href="#_1️⃣-大模型-llm-先学会-调用-和-提示" aria-label="Permalink to “1️⃣ 大模型（LLM）：先学会“调用”和“提示””">​</a></h3><p><strong>阶段目标：</strong></p><ul><li>知道 LLM 是什么，有哪些主流模型（GPT、通义千问、LLaMA 等）。</li><li>能通过 API 调用模型，实现：问答、摘要、生成文案/代码。</li><li>会写基本的 Prompt，让模型输出更符合预期。</li></ul><p><strong>建议学习内容：</strong></p><ul><li><strong>基础了解：</strong><ul><li>什么是 LLM / GPT / Qwen / LLaMA，大致能力和区别。</li><li>看一眼 OpenAI / 通义 / Moonshot 等官方 API 文档，知道请求/响应长什么样。</li></ul></li><li><strong>调用练手：</strong><ul><li>用 Python 或 JavaScript 写几个小脚本： <ul><li>给一段新闻，让模型输出<strong>三句话摘要</strong>。</li><li>给一段产品说明，让模型写<strong>面试自我介绍</strong>或<strong>卖点总结</strong>。</li></ul></li></ul></li><li><strong>Prompt 设计基础：</strong><ul><li>几个核心概念：<strong>Zero-shot / Few-shot / Chain-of-Thought（思维链）</strong>。</li><li>练习：给模型「角色 + 目标 + 输入格式 + 输出格式」；试比较不同 Prompt 的效果。</li></ul></li></ul><p><strong>推荐工具：</strong></p><ul><li>OpenAI Playground、阿里通义的在线控制台。</li><li>Hugging Face Hub（看看有哪些开源模型）。</li><li>官方 API 文档（多翻几遍，比网文更靠谱）。</li></ul><p><strong>练手小项目建议：</strong></p><ul><li><strong>新闻摘要生成器</strong><ul><li>输入：一段新闻或一篇博客链接（简单可以先手动复制粘贴）。</li><li>输出：3 点摘要 + 一段“普通人能听懂的解释”。</li></ul></li><li><strong>简单问答机器人</strong><ul><li>做一个命令行或网页，前端一个输入框，后端调用 LLM 接口返回结果。</li></ul></li></ul><blockquote><p>这一阶段的关键是：<strong>先把“会用 API”变成肌肉记忆</strong>，不要一上来就研究模型结构和论文。</p></blockquote><hr><h3 id="_2️⃣-agent-工具型-ai-让模型-能干活" tabindex="-1">2️⃣ Agent / 工具型 AI：让模型“能干活” <a class="header-anchor" href="#_2️⃣-agent-工具型-ai-让模型-能干活" aria-label="Permalink to “2️⃣ Agent / 工具型 AI：让模型“能干活””">​</a></h3><p><strong>阶段目标：</strong></p><ul><li>理解什么是 Agent：<strong>模型 + 工具 + 任务规划</strong>。</li><li>学会用一个简单框架（比如 LangChain），让模型调用外部接口完成任务。</li></ul><p><strong>建议学习内容：</strong></p><ul><li><strong>了解常见框架：</strong><ul><li>LangChain（Python/TS）、AutoGPT、OpenAI 的 function calling / tools 等。</li></ul></li><li><strong>简单工具调用练手：</strong><ul><li>选一个简单工具 API：如天气 API、股票行情 API、汇率 API。</li><li>让模型根据用户指令： <ol><li>解析出需要调用哪个工具、需要什么参数。</li><li>调用 API 拿到数据。</li><li>用自然语言解释结果（比如：是否适合出门？股票是否波动很大？）。</li></ol></li></ul></li><li><strong>多步骤任务（Task Planning）</strong>： <ul><li>理解“让模型自己拆步骤”的概念：分析需求 → 规划步骤 → 逐步执行。</li></ul></li></ul><p><strong>练手小项目建议：</strong></p><ul><li><strong>投资小助手（简版）</strong><ul><li>输入：股票代码或币种。</li><li>Agent 流程： <ul><li>调用行情 API 获取当前价格/涨跌。</li><li>调用新闻 API 获取近期相关新闻。</li><li>让模型输出一段“风险提示 + 中立分析”（而不是直接给买卖建议）。</li></ul></li></ul></li><li><strong>自动化日程提醒</strong><ul><li>把日历/待办（可以先用本地 JSON 模拟）作为数据源。</li><li>AI 接收自然语言指令（比如“帮我看看这周哪天有空学习 3 小时”），给出整理后的建议。</li></ul></li></ul><hr><h2 id="三、第二阶段-数据接入与中间层-—-mvp-server-数据中台" tabindex="-1">三、第二阶段：数据接入与中间层 — MVP Server / 数据中台 <a class="header-anchor" href="#三、第二阶段-数据接入与中间层-—-mvp-server-数据中台" aria-label="Permalink to “三、第二阶段：数据接入与中间层 — MVP Server / 数据中台”">​</a></h2><h3 id="_3️⃣-mvp-server-让模型-吃到干净的数据" tabindex="-1">3️⃣ MVP Server：让模型“吃到干净的数据” <a class="header-anchor" href="#_3️⃣-mvp-server-让模型-吃到干净的数据" aria-label="Permalink to “3️⃣ MVP Server：让模型“吃到干净的数据””">​</a></h3><p><strong>阶段目标：</strong></p><ul><li>能写一个简单的<strong>中间层服务</strong>：把多种数据源（新闻、行情、数据库）整理成统一格式。</li><li>模型只需要调用你这个服务，就能拿到“结构化、干净的上下文数据”。</li></ul><p><strong>建议学习内容：</strong></p><ul><li><strong>API 设计基础：</strong><ul><li>REST 基本规范、常见状态码、简单的接口风格。</li><li>有余力可以看一下 GraphQL 的基本概念（非必须）。</li></ul></li><li><strong>数据清洗与标准化：</strong><ul><li>从 JSON / CSV / 数据库表中读取数据。</li><li>做字段统一：例如都整理成 <code>{ time, source, title, content, tag }</code> 这种格式。</li></ul></li><li><strong>中间层实践：</strong><ul><li>写一个小服务（Python FastAPI / Node.js / Spring Boot 均可）： <ul><li>定时爬取或拉取新闻、行情数据。</li><li>存入本地数据库或缓存。</li><li>对外提供一个统一的 <code>/ai/context</code> 接口，返回整理好的数据列表。</li></ul></li></ul></li></ul><p><strong>练手小项目建议：</strong></p><ul><li><strong>新闻 + 股票行情抓取服务（MVP）</strong><ul><li>任务： <ul><li>写一个脚本或服务： <ul><li>定时拉取新闻接口。</li><li>定时拉取某几个标的的价格。</li></ul></li><li>暴露一个接口： <ul><li><code>/context?symbol=xxx</code>，返回该标的最近 N 条新闻 + 价格走势。</li></ul></li></ul></li><li>后续：让你的 LLM/Agent <strong>优先调用这个中间层接口</strong>，再基于返回的数据做分析。</li></ul></li></ul><blockquote><p>这一阶段的思路是：<strong>别一上来就让模型去“满世界乱抓数据”，先自己搭一个小数据中台，再让模型来消费。</strong></p></blockquote><hr><h2 id="四、第三阶段-多模态-知识图谱-—-做更聪明的-ai-助手" tabindex="-1">四、第三阶段：多模态 &amp; 知识图谱 — 做更聪明的 AI 助手 <a class="header-anchor" href="#四、第三阶段-多模态-知识图谱-—-做更聪明的-ai-助手" aria-label="Permalink to “四、第三阶段：多模态 &amp; 知识图谱 — 做更聪明的 AI 助手”">​</a></h2><h3 id="_4️⃣-多模态-知识图谱-让检索和推理更-聪明" tabindex="-1">4️⃣ 多模态 / 知识图谱：让检索和推理更“聪明” <a class="header-anchor" href="#_4️⃣-多模态-知识图谱-让检索和推理更-聪明" aria-label="Permalink to “4️⃣ 多模态 / 知识图谱：让检索和推理更“聪明””">​</a></h3><p><strong>阶段目标：</strong></p><ul><li>掌握向量检索（RAG）的基本概念，能自己搭一个简单的“私有知识库问答系统”。</li><li>了解图数据库（如 Neo4j）的基本使用，知道什么时候需要图结构而不是平铺的表。</li></ul><p><strong>建议学习内容：</strong></p><ul><li><strong>向量检索基础（RAG）</strong>： <ul><li>Embedding（文本向量化）的概念：把文本变成向量，方便相似度搜索.</li><li>向量数据库：Milvus、Weaviate、Pinecone 等，至少会用其中一个。</li></ul></li><li><strong>多模态应用：</strong><ul><li>文本 + 图片：比如根据一张图和一段描述，做联合检索或问答。</li><li>文档问答：PDF/Markdown/网页内容切块，向量化后做检索。</li></ul></li><li><strong>知识图谱 / 图数据库：</strong><ul><li>Neo4j 基础：节点（Node）、关系（Relationship）、属性（Property）。</li><li>知道什么时候用图结构更适合：复杂关系、路径查询、推荐关系等。</li></ul></li></ul><p><strong>练手小项目建议：</strong></p><ul><li><strong>投资分析知识库（RAG + 简单图）</strong><ul><li>把历史新闻、公告、公司信息等整理成一个文档集合。</li><li>使用向量数据库搭一个“问答机器人”： <ul><li>例如问：“这家公司最近三个月有哪些利空消息？”</li></ul></li><li>可选进阶：用 Neo4j 把“公司—高管—事件—行业”之间的关系建成图，用来查询“关联风险”。</li></ul></li><li><strong>企业内部问答系统（简化版）</strong><ul><li>把自己写的学习笔记、规范文档（比如你这个面试笔记库）做成一个知识库。</li><li>做一个 Web 页面：输入问题 → 检索相关文档片段 → 让模型基于这些上下文回答。</li></ul></li></ul><hr><h2 id="五、第四阶段-可选-生成平台-mlops" tabindex="-1">五、第四阶段（可选）：生成平台 &amp; MLOps <a class="header-anchor" href="#五、第四阶段-可选-生成平台-mlops" aria-label="Permalink to “五、第四阶段（可选）：生成平台 &amp; MLOps”">​</a></h2><h3 id="_5️⃣-部署与运维-从-玩具-demo-走向可用产品" tabindex="-1">5️⃣ 部署与运维：从“玩具 DEMO”走向可用产品 <a class="header-anchor" href="#_5️⃣-部署与运维-从-玩具-demo-走向可用产品" aria-label="Permalink to “5️⃣ 部署与运维：从“玩具 DEMO”走向可用产品”">​</a></h3><p>这一阶段可以在你前面几步都比较熟练之后再考虑，属于<strong>“做产品和平台”</strong>的能力。</p><p><strong>阶段目标：</strong></p><ul><li>能把自己的 AI 服务部署到线上（本地服务器或云端）。</li><li>知道基本的日志、监控、版本管理，避免“改一版就把线上搞挂”。</li></ul><p><strong>建议学习内容：</strong></p><ul><li>Docker 基础，能给自己的服务写一个简单的 <code>Dockerfile</code>。</li><li>CI/CD 基础概念（例如 GitHub Actions、Jenkins），知道怎么自动构建和部署。</li><li>基本监控： <ul><li>接口 QPS、错误率、响应时间。</li><li>模型调用次数、失败率、延迟。</li></ul></li></ul><p><strong>练手小项目建议：</strong></p><ul><li>把你的“面试学习 Agent / 投资助手”做成一个简单 Web 服务： <ul><li>提供 HTTP 接口或一个基础 Web 页面。</li><li>用 Docker 打包，部署到一台云服务器。</li><li>加上基础日志记录，方便出问题时排查。</li></ul></li></ul><hr><h2 id="六、和你当前学习-求职主线的关系" tabindex="-1">六、和你当前学习/求职主线的关系 <a class="header-anchor" href="#六、和你当前学习-求职主线的关系" aria-label="Permalink to “六、和你当前学习/求职主线的关系”">​</a></h2><ul><li>这条 AI 路线是围绕你现有的 <strong>Java 面试笔记库 + 远程工作目标</strong> 设计的： <ul><li>阶段一：让 LLM 变成你的“高效助理”；</li><li>阶段二：让你的笔记和业务数据结构化，喂给模型吃；</li><li>阶段三：用 RAG/图谱做更聪明的知识助手；</li><li>阶段四：把这些能力真正部署出来，形成可以讲的项目经历。</li></ul></li></ul><p>当你能自然地对面试官说：“我有一套自己的面试学习 Agent / 知识库助手，从数据整理到部署上线都是我自己搭的”，这条路线的价值就完全体现出来了。</p>',62)])])}const c=i(n,[["render",a]]);export{d as __pageData,c as default};
